function validateCoupon(
  coupon: Coupon,
  cartTotal: number,
  currentDate: Date
): { valid: boolean; message?: string } {
  // Vérifier si le coupon est actif
  if (!coupon.isActive) {
    return { valid: false, message: 'Ce coupon n\'est plus actif' };
  }

  // Vérifier la période de validité
  if (currentDate < coupon.validFrom) {
    return { valid: false, message: 'Ce coupon n\'est pas encore valide' };
  }
  if (currentDate > coupon.validUntil) {
    return { valid: false, message: 'Ce coupon a expiré' };
  }

  // Vérifier le montant minimum
  if (coupon.minAmount && cartTotal < coupon.minAmount) {
    return {
      valid: false,
      message: `Montant minimum requis : ${coupon.minAmount} FCFA`,
    };
  }

  // Vérifier la limite d'utilisation
  if (coupon.maxUses && coupon.usageCount >= coupon.maxUses) {
    return { valid: false, message: 'Ce coupon a atteint sa limite d\'utilisation' };
  }

  return { valid: true };
}
