async generateUniqueCoupons(
  campaignId: string,
  count: number,
  baseCoupon: Partial<Coupon>
): Promise<Coupon[]> {
  const coupons: Coupon[] = [];
  const generatedCodes = new Set<string>();

  for (let i = 0; i < count; i++) {
    let code: string;
    let isUnique = false;

    while (!isUnique) {
      // Générer un code aléatoire (ex: BF-ABCD-1234)
      const randomPart = Math.random().toString(36).substring(2, 8).toUpperCase();
      code = `${baseCoupon.prefix || 'PROMO'}-${randomPart}`;

      if (!generatedCodes.has(code)) {
        const existing = await this.couponRepository.findOne({
          where: { code },
        });
        if (!existing) {
          isUnique = true;
          generatedCodes.add(code);
        }
      }
    }

    const coupon = this.couponRepository.create({
      ...baseCoupon,
      code,
      campaignId,
      usageCount: 0,
      isActive: true,
      validFrom: baseCoupon.validFrom || new Date(),
      validUntil: baseCoupon.validUntil || new Date(Date.now() + 30 * 24 * 60 * 60 * 1000), // +30 jours
    });

    coupons.push(coupon);
  }

  await this.couponRepository.save(coupons);
  return coupons;
}
```
